#!/usr/bin/env bash
# Verify baseline: check that all target files exist and are readable.
# Generated by the initializer agent -- edit to match your project.
set -e

PROJECT_ROOT="$(cd "$(dirname "$0")/.." && pwd)"

echo "Verifying baseline for Authenticity Gate harness run..."
echo "Project root: $PROJECT_ROOT"
echo ""

FAIL=0

check_file() {
  if [ -r "$PROJECT_ROOT/$1" ]; then
    echo "OK   -- $1"
  else
    echo "FAIL -- $1 (not found or not readable)"
    FAIL=1
  fi
}

# Check all 6 target files
check_file "plugins/harness/skills/harness/SKILL.md"
check_file "plugins/harness/skills/harness/references/patterns.md"
check_file "plugins/harness/agents/generator.md"
check_file "plugins/harness/skills/harness/roles/generator.md"
check_file "plugins/harness/agents/evaluator.md"
check_file "plugins/harness/skills/harness/roles/evaluator.md"

echo ""

# Check insertion point for F-001
if grep -q "Quantified Evaluation" "$PROJECT_ROOT/plugins/harness/skills/harness/SKILL.md" 2>/dev/null; then
  echo "OK   -- SKILL.md contains 'Quantified Evaluation' section (insertion point for F-001)"
else
  echo "FAIL -- SKILL.md missing 'Quantified Evaluation' section"
  FAIL=1
fi

# Check insertion points for F-002
if grep -q "NN-evaluation.json" "$PROJECT_ROOT/plugins/harness/skills/harness/references/patterns.md" 2>/dev/null; then
  echo "OK   -- patterns.md contains NN-evaluation.json template (insertion point for F-002)"
else
  echo "FAIL -- patterns.md missing NN-evaluation.json template"
  FAIL=1
fi

if grep -q "NN-builder-report.md" "$PROJECT_ROOT/plugins/harness/skills/harness/references/patterns.md" 2>/dev/null; then
  echo "OK   -- patterns.md contains NN-builder-report.md template (insertion point for F-002)"
else
  echo "FAIL -- patterns.md missing NN-builder-report.md template"
  FAIL=1
fi

echo ""

if [ "$FAIL" -eq 0 ]; then
  echo "Baseline verification PASSED -- all target files exist and insertion points confirmed."
else
  echo "Baseline verification FAILED -- see errors above."
  exit 1
fi
